function round(value: number, digits = 2) {
  if (!Number.isFinite(value)) return 0;
  const factor = 10 ** digits;
  return Math.round(value * factor) / factor;
}

function pluralUnit(unit: string) {
  return unit.endsWith("s") ? unit : `${unit}s`;
}

function singularUnit(unit: string) {
  return unit.replace(/s$/, "");
}

function formatAmount(value: number) {
  if (!Number.isFinite(value)) return "0";
  if (Math.abs(value) >= 100) return Math.round(value).toLocaleString();
  if (Math.abs(value) >= 10) return round(value, 1).toLocaleString();
  return round(value, 2).toLocaleString();
}

function convertScaledAmount(amount: number, unit: string) {
  if (unit === "teaspoons" && amount >= 3) return `${formatAmount(amount / 3)} tbsp`;
  if (unit === "tablespoons" && amount >= 16) return `${formatAmount(amount / 16)} cups`;
  if (unit === "ounces" && amount >= 16) return `${formatAmount(amount / 16)} lb`;
  if (unit === "grams" && amount >= 1000) return `${formatAmount(amount / 1000)} kg`;
  if (unit === "milliliters" && amount >= 1000) return `${formatAmount(amount / 1000)} L`;
  return `${formatAmount(amount)} ${unit}`;
}

