      <div className="mt-5 space-y-3">{items.map((item, index) => <div key={index} className="grid gap-3 rounded-xl border border-border bg-background/50 p-3 sm:grid-cols-[1fr_0.6fr_auto]"><select className={SELECT_CLASS} value={item.type} onChange={(e) => setItems((list) => list.map((row, i) => i === index ? { ...row, type: e.target.value } : row))}>{Object.keys(ALCOHOL_ITEMS).map((name) => <option key={name}>{name}</option>)}</select><input className={INPUT_CLASS} type="number" min="0" value={item.quantity} onChange={(e) => setItems((list) => list.map((row, i) => i === index ? { ...row, quantity: Number(e.target.value) } : row))} /><button type="button" className="h-12 rounded-xl border border-border px-4 text-sm font-bold text-muted-foreground hover:bg-muted" onClick={() => setItems((list) => list.filter((_, i) => i !== index))}>Remove</button></div>)}</div>
