function IntermittentFastingCalculator() {
  const [protocol, setProtocol] = useState("16:8");
  const [start, setStart] = useState("12:00");
  const protocolMap: Record<string, [number, number]> = { "16:8": [16, 8], "18:6": [18, 6], "20:4": [20, 4], OMAD: [23, 1], "12:12": [12, 12], "5:2": [0, 24], ADF: [36, 12] };
  const [, eatHours] = protocolMap[protocol];
  const startHour = Number(start.split(":")[0]) + Number(start.split(":")[1] || 0) / 60;
  const endHour = (startHour + eatHours) % 24;
  const fmt = (h: number) => `${String(Math.floor(h) % 24).padStart(2, "0")}:${String(Math.round((h % 1) * 60)).padStart(2, "0")}`;
  return (
    <CalculatorShell badge="IF schedule" title="Calculate fasting and eating windows" results={<div className="space-y-4"><div className="grid gap-3 sm:grid-cols-2"><MetricCard label="Eating window" value={`${start} - ${fmt(endHour)}`} /><MetricCard label="Fasting window" value={`${fmt(endHour)} - ${start}`} /><MetricCard label="First meal" value={start} /><MetricCard label="Last meal" value={fmt(Math.max(startHour, endHour - 1))} /></div><div className="h-5 overflow-hidden rounded-full border border-border bg-muted"><div className="h-full bg-primary" style={{ width: `${Math.min(100, (eatHours / 24) * 100)}%` }} /></div></div>}>
      <div className="grid gap-4 sm:grid-cols-3"><Field label="Fasting Protocol"><select className={SELECT_CLASS} value={protocol} onChange={(e) => setProtocol(e.target.value)}><option>16:8</option><option>18:6</option><option>20:4</option><option>OMAD</option><option>5:2</option><option value="ADF">Alternate day fasting</option><option>12:12</option></select></Field><Field label="Eating Window Start"><input className={INPUT_CLASS} type="time" value={start} onChange={(e) => setStart(e.target.value)} /></Field><Field label="Wake/Sleep Context"><input className={INPUT_CLASS} value="Adjust start time to fit your day" readOnly /></Field></div>
    </CalculatorShell>
  );
}

function KetoCalculator() {
  const [age, setAge] = useState(35);
  const [gender, setGender] = useState<"male" | "female">("female");
  const [height, setHeight] = useState(165);
  const [weight, setWeight] = useState(75);
  const [activity, setActivity] = useState(1.375);
  const [goal, setGoal] = useState("loss");
  const bmr = 10 * weight + 6.25 * height - 5 * age + (gender === "male" ? 5 : -161);
  const calories = bmr * activity + (goal === "gain" ? 200 : goal === "loss" ? -400 : 0);
  const protein = weight * 2.20462 * (goal === "gain" ? 0.85 : 0.7);
  const carbs = goal === "performance" ? 50 : 25;
  const fat = Math.max(0, (calories - protein * 4 - carbs * 4) / 9);
  return (
    <CalculatorShell badge="Keto macros" title="Calculate ketogenic diet macros" results={<div className="grid gap-3 sm:grid-cols-2"><MetricCard label="Daily calories" value={Math.round(calories)} /><MetricCard label="Protein" value={`${Math.round(protein)} g`} /><MetricCard label="Net carbs" value={`${carbs} g`} note="Typical ketosis range: 20-50g" /><MetricCard label="Fat" value={`${Math.round(fat)} g`} /><MetricCard label="Keto split" value={`${Math.round((fat * 9 / calories) * 100)}% fat`} note={`${Math.round((protein * 4 / calories) * 100)}% protein, ${Math.round((carbs * 4 / calories) * 100)}% carbs`} /></div>}>
      <div className="grid gap-4 sm:grid-cols-2"><Field label="Age"><input className={INPUT_CLASS} type="number" value={age} onChange={(e) => setAge(Number(e.target.value))} /></Field><Field label="Gender"><select className={SELECT_CLASS} value={gender} onChange={(e) => setGender(e.target.value as "male" | "female")}><option value="female">Female</option><option value="male">Male</option></select></Field><Field label="Height (cm)"><input className={INPUT_CLASS} type="number" value={height} onChange={(e) => setHeight(Number(e.target.value))} /></Field><Field label="Weight (kg)"><input className={INPUT_CLASS} type="number" value={weight} onChange={(e) => setWeight(Number(e.target.value))} /></Field><Field label="Activity"><select className={SELECT_CLASS} value={activity} onChange={(e) => setActivity(Number(e.target.value))}><option value={1.2}>Sedentary</option><option value={1.375}>Light activity</option><option value={1.55}>Moderate activity</option><option value={1.725}>Very active</option></select></Field><Field label="Keto Goal"><select className={SELECT_CLASS} value={goal} onChange={(e) => setGoal(e.target.value)}><option value="loss">Weight loss</option><option value="maintenance">Maintenance</option><option value="gain">Muscle building</option><option value="performance">Athletic performance keto</option></select></Field></div>
    </CalculatorShell>
  );
}

